private IneqTree Tooth()
{
  IneqTree res = new IneqTree();
  
  for(int i=0; i < 4; i++)
  {
    IneqTree t = ((# x + z - 0.5) & (# -x + z - 0.5));
    
    int ii = i;
    
	t.Transform(delegate(ref double x, ref double y, ref double z)
		{
          double a = (double)ii * PI /4;
          double x1 = x * cos(a) - y * sin(a);
          double y1 = x * sin(a) + y * cos(a);
          x = x1; y = y1;         
        });      
    
    res = res | t;
  }
  
  return res;
}

private IneqTree Egg(bool top)
{
  	var sdf = new SignedDistance("Earth.stl");
  
  	IneqTree f = new IneqTree((x, y, z) => {
      double s1 = 1.2;
      double s2 = 1.7;
      double s = s1 + (s2-s1)*(z+1)/2;
      x *= s; y *= s;
      return sdf.From(x,y,z);
      //return sqrt(x*x + y*y + z*z) - 1.0 * 1.0;
    });
  
    IneqTree fb = new IneqTree((x, y, z) => {
      double s1 = 1.2;
      double s2 = 1.7;
      double s = s1 + (s2-s1)*(z+1)/2;
      x *= s; y *= s;      
      
      return sqrt(x*x + y*y + z*z) - 0.95 * 0.95;
    });
  
	if(top)
    {
		return f & !fb & !Tooth();        
    }
  	else
    {
		var d = (# z + 0.75);
      	var d1 = (# z + 0.85);
		return f & (!fb | d) & !d1 & Tooth();        
    }	  
}

